answer.programlisting:
#!/usr/bin/env python3 import argparse import time import tomllib
def generate_ldif(toml_path, output_path): # 1. Directly read the TOML file with open(toml_path, "rb") as f: data = tomllib.load(f)
cfg, users = data["global"], data["users"] base_dn = cfg["base_dn"] domain = ".".join(p[3:] for p in base_dn.split(",") if p.startswith("dc=")) shadow_day = int(time.time() // 86400)
with open(output_path, "w", encoding="utf-8") as ldif: # 2. Generate private groups (UPG) ldif.write("# --- PRIVATE GROUPS (UPG) ---
") for idx, u in enumerate(users): gid = cfg["start_id"] + idx ldif.write( f"dn: cn={u['uid']},{cfg['groups_ou']},{base_dn}
" f"objectClass: posixGroup
cn: {u['uid']}
gidNumber: {gid}

" )
# 3. Generate user accounts ldif.write("# --- USER ACCOUNTS ---
") for idx, u in enumerate(users): uid = cfg["start_id"] + idx full_name = f"{u['firstname']} {u['lastname']}" password_hash = u["password_hash"] ldif.write( f"dn: uid={u['uid']},{cfg['users_ou']},{base_dn}
" "objectClass: inetOrgPerson
objectClass: posixAccount
objectClass: shadowAccount
" f"uid: {u['uid']}
cn: {full_name}
givenName: {u['firstname']}
sn: {u['lastname']}
" f"mail: {u['uid']}@{domain}
userPassword: {password_hash}
" f"shadowLastChange: {shadow_day}
loginShell: {cfg['default_shell']}
" f"uidNumber: {uid}
gidNumber: {uid}
" f"homeDirectory: {cfg['default_home_base']}/{u['uid']}
gecos: {full_name}

" )
# 4. Generate the shared system group ldif.write( "# --- SHARED SYSTEM GROUP ---
" f"dn: cn={cfg['shared_group_name']},{cfg['groups_ou']},{base_dn}
" f"objectClass: posixGroup
cn: {cfg['shared_group_name']}
" f"gidNumber: {cfg['shared_group_gid']}
" ) for u in users: ldif.write(f"memberUid: {u['uid']}
")
print( f"Success: generated '{output_path}' with membership in group {cfg['shared_group_name']}." )
if __name__ == "__main__": parser = argparse.ArgumentParser(description="Directory LDIF generator.") parser.add_argument("toml", nargs="?", default="skywalkers.toml") parser.add_argument("output", nargs="?", default="import_skywalkers.ldif") args = parser.parse_args() generate_ldif(args.toml, args.output)

#!/bin/bash
DOMAIN="lab.local" HOSTS_FILE="/etc/hosts" CLIENT_IPS=( "172.28.101.4" "2001:678:3fc:65:baad:caff:fefe:4" ) CLIENT_NAME="ldap-clnt" SERVER_IPS=( "172.28.101.3" "2001:678:3fc:65:baad:caff:fefe:3" ) SERVER_NAME="ldap-srvr"
if [[ ${EUID} -ne 0 ]]; then echo "This script must be run as root." >&2 exit 1 fi
# Escape the characters that are special in a sed basic regular expression. escape_sed_bre() { sed 's/[][\\.^$*]/\\&/g' }
update_host_entry() { local ip="$1" local name="$2" # Escape the IP before using it inside a sed search pattern. local escaped_ip escaped_ip=$(printf '%s\n' "${ip}" | escape_sed_bre) sed -i "/^${escaped_ip}[[:space:]]/d" "${HOSTS_FILE}" echo "${ip} ${name}.${DOMAIN} ${name}" >>"${HOSTS_FILE}" }
for ip in "${CLIENT_IPS[@]}"; do update_host_entry "${ip}" "${CLIENT_NAME}" done
for ip in "${SERVER_IPS[@]}"; do update_host_entry "${ip}" "${SERVER_NAME}" done
exit 0

